function diff(oldNode, newNode, path) {
  path = path || 'root';

  if (!oldNode && newNode) {
    console.log(path + ': ADD ' + newNode.type);
    return;
  }
  if (oldNode && !newNode) {
    console.log(path + ': REMOVE ' + oldNode.type);
    return;
  }
  if (typeof oldNode === 'string' && typeof newNode === 'string') {
    if (oldNode !== newNode) {
      console.log(path + ': TEXT_CHANGE "' + oldNode + '" -> "' + newNode + '"');
    }
    return;
  }
  if (oldNode.type !== newNode.type) {
    console.log(path + ': REPLACE ' + oldNode.type + ' -> ' + newNode.type);
    return;
  }
  console.log(path + ': UPDATE ' + oldNode.type);

  // Diff children
  const oldChildren = Array.isArray(oldNode.props.children) ? oldNode.props.children : [oldNode.props.children].filter(Boolean);
  const newChildren = Array.isArray(newNode.props.children) ? newNode.props.children : [newNode.props.children].filter(Boolean);
  const maxLen = Math.max(oldChildren.length, newChildren.length);
  for (let i = 0; i < maxLen; i++) {
    diff(oldChildren[i], newChildren[i], path + '/' + (newChildren[i]?.type || oldChildren[i]?.type || 'text') + '[' + i + ']');
  }
}

