function reconcileByIndex(oldList, newList) {
  console.log('Index-based reconciliation:');
  let ops = 0;
  for (let i = 0; i < Math.max(oldList.length, newList.length); i++) {
    if (i >= oldList.length) {
      console.log('  [' + i + '] ADD: ' + newList[i].value);
      ops++;
    } else if (i >= newList.length) {
      console.log('  [' + i + '] REMOVE: ' + oldList[i].value);
      ops++;
    } else if (oldList[i].value !== newList[i].value) {
      console.log('  [' + i + '] UPDATE: ' + oldList[i].value + ' -> ' + newList[i].value);
      ops++;
    } else {
      console.log('  [' + i + '] KEEP: ' + oldList[i].value);
    }
  }
  console.log('  Total operations: ' + ops);
}

function reconcileByKey(oldList, newList) {
  console.log('Key-based reconciliation:');
  let ops = 0;
  const oldMap = {};
  oldList.forEach((item, i) => { oldMap[item.key] = { ...item, index: i }; });

  newList.forEach((item, newIndex) => {
    const old = oldMap[item.key];
    if (!old) {
      console.log('  [' + newIndex + '] ADD: ' + item.value);
      ops++;
    } else if (old.index !== newIndex) {
      console.log('  [' + newIndex + '] MOVE: ' + item.value + ' (from index ' + old.index + ')');
      ops++;
    } else {
      console.log('  [' + newIndex + '] KEEP: ' + item.value);
    }
  });
  console.log('  Total operations: ' + ops);
}

const oldList = [
  { key: 'a', value: 'A' },
  { key: 'b', value: 'B' },
  { key: 'c', value: 'C' },
  { key: 'd', value: 'D' }
