function simulateLifecycle() {
  let mounted = false;
  let subscription = null;
  let prevUserId = null;

  function mount(userId) {
    mounted = true;
    console.log('--- MOUNT ---');
    console.log('Render: userId=' + userId);

    // Effect 1: subscription (mount only)
    subscription = 'EventBus-sub-' + Date.now();
    console.log('Effect 1: Subscribed (' + subscription + ')');

    // Effect 2: fetch (depends on userId)
    console.log('Effect 2: Fetching user ' + userId);
    prevUserId = userId;
  }

  function update(userId) {
    console.log('--- UPDATE ---');
    console.log('Render: userId=' + userId);

    // Effect 2: cleanup previous, then run
    if (userId !== prevUserId) {
      console.log('Effect 2 cleanup: Cancel fetch for user ' + prevUserId);
      console.log('Effect 2: Fetching user ' + userId);
      prevUserId = userId;
    } else {
      console.log('Effect 2: Skipped (userId unchanged)');
    }
  }

  function unmount() {
    console.log('--- UNMOUNT ---');
    // All cleanups run
    console.log('Effect 1 cleanup: Unsubscribed (' + subscription + ')');
    console.log('Effect 2 cleanup: Cancel fetch for user ' + prevUserId);
    mounted = false;
    subscription = null;
  }

  mount(1);
  update(1);
  update(2);
  unmount();
}

simulateLifecycle();

