function simulateEffects() {
  let effectBRan = false;
  let prevCount = undefined;

  function render(renderNum, count) {
    console.log('=== Render ' + renderNum + ' (count=' + count + ') ===');

    // Effect A: no deps — runs every render
    console.log('  Effect A: ran (no deps - every render)');

    // Effect B: [] — mount only
    if (!effectBRan) {
      console.log('  Effect B: ran (mount only)');
      effectBRan = true;
    } else {
      console.log('  Effect B: skipped (already mounted)');
    }

    // Effect C: [count] — when count changes
    if (prevCount !== count) {
      if (prevCount !== undefined) {
        console.log('  Effect C cleanup: cleaned up for count=' + prevCount);
      }
      console.log('  Effect C: ran (count changed to ' + count + ')');
      prevCount = count;
    } else {
      console.log('  Effect C: skipped (count unchanged)');
    }
  }

  render(1, 0);  // Mount
  render(2, 0);  // Update, count unchanged
  render(3, 1);  // Update, count changed

  // Unmount
  console.log('=== Unmount ===');
  console.log('  Effect A cleanup: ran');
  console.log('  Effect B cleanup: ran');
  console.log('  Effect C cleanup: cleaned up for count=' + prevCount);
}

simulateEffects();

