function simulateControlled(keystrokes) {
  console.log('=== Controlled ===');
  let state = '';

  keystrokes.forEach(key => {
    state += key;
    const isValid = state.includes('@');
    console.log('Keystroke: "' + key + '" | State: "' + state + '" | Valid: ' + isValid);
  });

  console.log('Final state: "' + state + '"');
}

function simulateUncontrolled(keystrokes) {
  console.log('=== Uncontrolled ===');
  let domValue = '';

  keystrokes.forEach(key => {
    domValue += key;
    console.log('Keystroke: "' + key + '" | DOM value: "' + domValue + '" | React knows: nothing');
  });

  // Only on submit do we read the value
  console.log('Submit! Reading ref: "' + domValue + '"');
  const isValid = domValue.includes('@');
  console.log('Valid: ' + isValid);
}

simulateControlled(['a', '@', 'b']);
console.log('');
simulateUncontrolled(['a', '@', 'b']);

