// Render 1: useState('A'), useState('B')
// Render 2: useState('A'), useState('B')  -> OK
// Render 3: useState('B')  -> VIOLATION (different order/count)

exercises.solution:
function createHooksSystem() {
  let hookOrder = [];
  let currentIndex = 0;
  let isFirstRender = true;

  return {
    useState: (label) => {
      if (isFirstRender) {
        hookOrder.push(label);
        console.log('  Hook ' + currentIndex + ': useState("' + label + '") - registered');
      } else {
        if (currentIndex >= hookOrder.length) {
          console.log('  Hook ' + currentIndex + ': useState("' + label + '") - VIOLATION! More hooks than first render');
        } else if (hookOrder[currentIndex] !== label) {
          console.log('  Hook ' + currentIndex + ': useState("' + label + '") - VIOLATION! Expected "' + hookOrder[currentIndex] + '"');
        } else {
          console.log('  Hook ' + currentIndex + ': useState("' + label + '") - OK');
        }
      }
      currentIndex++;
    },
    endRender: () => {
      if (!isFirstRender && currentIndex < hookOrder.length) {
        console.log('  VIOLATION! Fewer hooks (' + currentIndex + ') than first render (' + hookOrder.length + ')');
      }
      isFirstRender = false;
      currentIndex = 0;
    }
  };
}

const hooks = createHooksSystem();

console.log('Render 1 (establishes order):');
hooks.useState('name');
hooks.useState('email');
hooks.endRender();

console.log('Render 2 (same order - OK):');
hooks.useState('name');
hooks.useState('email');
hooks.endRender();

console.log('Render 3 (wrong order - violation):');
hooks.useState('email');
hooks.useState('name');
hooks.endRender();

console.log('Render 4 (missing hook - violation):');
hooks.useState('name');
hooks.endRender();
